import time

def step(grid):
    rows, cols = len(grid), len(grid[0])
    next_g = [[0]*cols for _ in range(rows)]
    for r in range(rows):
        for c in range(cols):
            neighbors = sum(
                grid[(r+dr) % rows][(c+dc) % cols]
                for dr in (-1,0,1) for dc in (-1,0,1)
                if (dr,dc) != (0,0))
            next_g[r][c] = int(neighbors==3 or (grid[r][c] and neighbors==2))
    return next_g

